@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes with our community.</p>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in categories)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h3 class="card-title">@category.Icon @category.Name</h3>
                    <p class="card-text">@category.Description</p>
                    <a href="@($"categories/{category.Slug}")" class="btn btn-primary">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private readonly List<Category> categories = new()
    {
        new("Breakfast", "breakfast", "Start your day right with these morning favorites.", "🥞"),
        new("Main Courses", "main-courses", "Hearty meals for lunch and dinner.", "🍝"),
        new("Desserts", "desserts", "Sweet treats to end any meal.", "🍰"),
        new("Soups & Salads", "soups-salads", "Light and refreshing options.", "🥗"),
        new("Appetizers", "appetizers", "Perfect starters for any gathering.", "🧆"),
        new("Beverages", "beverages", "Drinks to complement your meal.", "🍹")
    };

    private record Category(string Name, string Slug, string Description, string Icon);
}

