@page "/categories/{Slug}"

<PageTitle>@GetCategoryName() - RecipeShare</PageTitle>

<h1>@GetCategoryName()</h1>
<p><a href="/">← Back to Categories</a></p>

@if (GetRecipes() is { Count: > 0 } recipes)
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">@recipe.Summary</p>
                        <a href="@($"recipes/{recipe.Id}")" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category yet.</p>
}

@code {
    [Parameter]
    public string Slug { get; set; } = "";

    private string GetCategoryName() => Slug switch
    {
        "breakfast" => "Breakfast",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "soups-salads" => "Soups & Salads",
        "appetizers" => "Appetizers",
        "beverages" => "Beverages",
        _ => "Category"
    };

    private List<RecipeItem> GetRecipes() => Slug switch
    {
        "breakfast" => new()
        {
            new(1, "Fluffy Pancakes", "Light and airy pancakes perfect for a lazy weekend morning."),
            new(2, "Avocado Toast", "Creamy avocado on crispy sourdough with a hint of lemon.")
        },
        "main-courses" => new()
        {
            new(3, "Spaghetti Carbonara", "Classic Italian pasta with egg, cheese, and pancetta."),
            new(4, "Grilled Chicken Bowl", "Juicy grilled chicken over rice with fresh vegetables.")
        },
        "desserts" => new()
        {
            new(5, "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center."),
            new(6, "Lemon Tart", "Tangy lemon curd in a buttery pastry shell.")
        },
        _ => new()
    };

    private record RecipeItem(int Id, string Title, string Summary);
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted for review.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="6"
                placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool submitted;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the preparation steps.")]
        public string Steps { get; set; } = "";
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= currentRating ? "filled" : "")"
              @onclick="() => SetRating(star)"
              role="button"
              title="@star star(s)">
            @(star <= currentRating ? "★" : "☆")
        </span>
    }
    @if (currentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @currentRating/5</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;

    private void SetRating(int rating)
    {
        currentRating = rating;
    }
}

.star-rating {
    font-size: 1.8rem;
    display: inline-flex;
    align-items: center;
    gap: 0.1rem;
}

.star {
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star.filled {
    color: #f5a623;
}

.star:hover {
    color: #f5a623;
}

