                </div>
            </div>
        }
    </div>
}
else
{
    <p class="text-muted">No recipes found in this category yet.</p>
}

@code {
    [Parameter]
    public string Slug { get; set; } = "";

    private string GetCategoryName() => Slug switch
    {
        "breakfast" => "Breakfast",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "soups-salads" => "Soups & Salads",
        "appetizers" => "Appetizers",
        "beverages" => "Beverages",
