@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted for review.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="6"
                placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool submitted;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the preparation steps.")]
        public string Steps { get; set; } = "";
    }
}

